IF EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID('QMS_CHECKLIST_ASSIGNMENT') AND name = 'COMMENTS' AND system_type_id IN (35, 99)) ALTER TABLE QMS_CHECKLIST_ASSIGNMENT ALTER COLUMN COMMENTS NVARCHAR(MAX);
IF EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID('QMS_CHECKLIST_ASSIGNMENT') AND name = 'FILE_PATHS' AND system_type_id IN (35, 99)) ALTER TABLE QMS_CHECKLIST_ASSIGNMENT ALTER COLUMN FILE_PATHS NVARCHAR(MAX);
IF EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID('QMS_CHECKLIST_ASSIGNMENT') AND name = 'REMARKS' AND system_type_id IN (35, 99)) ALTER TABLE QMS_CHECKLIST_ASSIGNMENT ALTER COLUMN REMARKS NVARCHAR(MAX);
